from llama_index.core import PromptTemplate
qa_prompt = PromptTemplate( """You are a knowledge assistant. Answer ONLY from the context below. If the context does not contain the answer, say "I don't have that in my knowledge base." Always cite sources as [Source: {filename}, page {page}].
Context: {context_str}
Question: {query_str}
Answer:""" )
query_engine = index.as_query_engine( similarity_top_k=20, node_postprocessors=[reranker], response_mode="compact", text_qa_template=qa_prompt, )
